fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    if n == 0 {
        return vec![];
    }
    if n == 1 {
        return vec![0];
    }

    let lcp = |s: &str, t: &str| {
        let mut len = 0;
        while len < s.len() && len < t.len() && s.as_bytes()[len] == t.as_bytes()[len] {
            len += 1;
        }
        len
    };

    let mut lcp_array = vec![0; n - 1];
    for i in 0..n - 1 {
        lcp_array[i] = lcp(&words[i], &words[i + 1]);
    }

    let mut prefix_max = vec![0; n - 1];
    prefix_max[0] = lcp_array[0];
    for i in 1..n - 1 {
        prefix_max[i] = std::cmp::max(prefix_max[i - 1], lcp_array[i]);
    }

    let mut suffix_max = vec![0; n - 1];
    suffix_max[n - 2] = lcp_array[n - 2];
    for i in (0..n - 2).rev() {
        suffix_max[i] = std::cmp::max(suffix_max[i + 1], lcp_array[i]);
    }

    let mut answer = vec![0; n];
    for i in 0..n {
        let mut original_max = 0;
        if i == 0 {
            if n == 1 {
                original_max = 0;
            } else {
                original_max = if n - 2 >= 1 { suffix_max[1] } else { 0 };
            }
        } else if i == n - 1 {
            original_max = if n - 2 >= 0 { prefix_max[n - 2] } else { 0 };
        } else {
            let left = if i - 2 >= 0 { prefix_max[i - 2] } else { 0 };
            let right = if i + 1 <= n - 2 { suffix_max[i + 1] } else { 0 };
            original_max = std::cmp::max(left, right);
        }
        let mut new_pair_lcp = 0;
        if i > 0 && i < n - 1 {
            let s = &words[i - 1];
            let t = &words[i + 1];
            new_pair_lcp = lcp(s, t);
        }
        answer[i] = std::cmp::max(original_max, new_pair_lcp) as i64;
    }
    answer
}
